package com.example.flashcardapp.data.datasource.remote.model

import java.time.Instant

data class ApiResponse<T>(
    val status: Int,
    val message: String?,
    val data: T?,
    val timestamp: Instant? = null
) {
    fun isSuccess(): Boolean = status == 200
}

package com.example.flashcardapp.data.repository

import com.example.flashcardapp.data.datasource.local.session.AuthSessionStore
import com.example.flashcardapp.data.datasource.remote.auth.AuthRemoteDataSource
import com.example.flashcardapp.data.datasource.remote.model.auth.ForgotPasswordRequest
import com.example.flashcardapp.data.datasource.remote.model.auth.ForgotPasswordResponse
import com.example.flashcardapp.data.datasource.remote.model.auth.LoginRequest
import com.example.flashcardapp.data.datasource.remote.model.auth.LoginResponse
import com.example.flashcardapp.data.datasource.remote.model.auth.RegisterRequest
import com.example.flashcardapp.data.datasource.remote.model.auth.RegisterResponse
import com.example.flashcardapp.domain.repository.AuthRepository as DomainAuthRepository

class AuthRepositoryImpl(
    private val remoteDataSource: AuthRemoteDataSource,
    private val sessionStore: AuthSessionStore
) : DomainAuthRepository {

    override suspend fun login(request: LoginRequest): Result<LoginResponse> {
        return remoteDataSource.login(request)
    }

    override suspend fun register(request: RegisterRequest): Result<RegisterResponse> {
        return remoteDataSource.register(request)
    }

    override suspend fun forgotPassword(request: ForgotPasswordRequest): Result<ForgotPasswordResponse> {
        return remoteDataSource.forgotPassword(request)
    }

    override fun saveLoginSession(accessToken: String?) {
        sessionStore.saveLoginSession(accessToken)
    }

    override fun clearLoginSession() {
        sessionStore.clearLoginSession()
    }
}

package com.example.flashcardapp.data.repository

import com.example.flashcardapp.data.datasource.local.session.AuthSessionStore
import com.example.flashcardapp.data.datasource.remote.auth.AuthRemoteDataSource
import com.example.flashcardapp.data.datasource.remote.model.auth.ForgotPasswordRequest
import com.example.flashcardapp.data.datasource.remote.model.auth.ForgotPasswordResponse
import com.example.flashcardapp.data.datasource.remote.model.auth.LoginRequest
import com.example.flashcardapp.data.datasource.remote.model.auth.LoginResponse
import com.example.flashcardapp.data.datasource.remote.model.auth.RegisterRequest
import com.example.flashcardapp.data.datasource.remote.model.auth.RegisterResponse
import com.example.flashcardapp.domain.repository.AuthRepository as DomainAuthRepository
import kotlinx.coroutines.CoroutineDispatcher
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext

class AuthRepositoryImpl(
    private val remoteDataSource: AuthRemoteDataSource,
    private val sessionStore: AuthSessionStore,
    private val ioDispatcher: CoroutineDispatcher = Dispatchers.IO
) : DomainAuthRepository {

    override suspend fun login(request: LoginRequest): Result<LoginResponse> = withContext(ioDispatcher) {
        remoteDataSource.login(request)
    }

    override suspend fun register(request: RegisterRequest): Result<RegisterResponse> = withContext(ioDispatcher) {
        remoteDataSource.register(request)
    }

    override suspend fun forgotPassword(request: ForgotPasswordRequest): Result<ForgotPasswordResponse> = withContext(ioDispatcher) {
        remoteDataSource.forgotPassword(request)
    }

    override fun saveLoginSession(accessToken: String?) {
        sessionStore.saveLoginSession(accessToken)
    }

    override fun clearLoginSession() {
        sessionStore.clearLoginSession()
    }
}

package com.example.flashcardapp.presentation.feature.auth

import android.os.Bundle
import android.view.View
import android.widget.Toast
import androidx.core.widget.doAfterTextChanged
import androidx.fragment.app.Fragment
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.Lifecycle
import androidx.lifecycle.lifecycleScope
import androidx.lifecycle.repeatOnLifecycle
import androidx.navigation.fragment.findNavController
import com.example.flashcardapp.R
import com.example.flashcardapp.databinding.FragmentForgotPasswordBinding
import com.example.flashcardapp.di.AuthModule
import com.example.flashcardapp.presentation.common.dialog.authDialog.CheckEmailDialogFragment
import com.google.android.material.bottomnavigation.BottomNavigationView
import com.google.android.material.floatingactionbutton.FloatingActionButton
import kotlinx.coroutines.launch

class ForgotPasswordFragment : Fragment(R.layout.fragment_forgot_password) {

    private var _binding: FragmentForgotPasswordBinding? = null
    private val binding get() = _binding!!

    private lateinit var viewModel: ForgotPasswordViewModel

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)
        _binding = FragmentForgotPasswordBinding.bind(view)

        setupViewModel()
        setupListeners()
        observeViewModel()
    }

    override fun onResume() {
        super.onResume()
        hideMainChrome()
    }

    override fun onDestroyView() {
        _binding = null
        super.onDestroyView()
    }

    private fun setupViewModel() {
        val useCases = AuthModule.provideAuthUseCases(requireContext())
        viewModel = ViewModelProvider(
            this,
            AuthViewModelFactory(useCases)
        )[ForgotPasswordViewModel::class.java]
    }

    private fun setupListeners() {
        binding.buttonBack.setOnClickListener {
            findNavController().popBackStack()
        }
        binding.buttonSendVerificationCode.setOnClickListener {
            viewModel.submit()
        }
        binding.inputEmail.doAfterTextChanged {
            viewModel.onEmailChanged(it?.toString().orEmpty())
        }
    }

    private fun observeViewModel() {
        viewLifecycleOwner.lifecycleScope.launch {
            viewLifecycleOwner.repeatOnLifecycle(Lifecycle.State.STARTED) {
                launch {
                    viewModel.formState.collect { state ->
                        binding.layoutEmail.error = state.emailError
                    }
                }

                launch {
                    viewModel.uiState.collect { state ->
                        when (state) {
                            AuthOperationState.Idle -> renderLoading(false)
                            AuthOperationState.Loading -> renderLoading(true)
                            is AuthOperationState.Success -> {
                                renderLoading(false)
                                showCheckEmailDialog(state.email)
                            }

                            is AuthOperationState.Error -> {
                                renderLoading(false)
                                Toast.makeText(requireContext(), state.message, Toast.LENGTH_SHORT).show()
                                viewModel.resetUiState()
                            }
                        }
                    }
                }
            }
        }
    }

    private fun renderLoading(isLoading: Boolean) {
        binding.buttonSendVerificationCode.isEnabled = !isLoading
        binding.buttonSendVerificationCode.alpha = if (isLoading) 0.7f else 1f
    }

    private fun showCheckEmailDialog(email: String?) {
        val dialog = CheckEmailDialogFragment.newInstance(email)
        dialog.setOnUnderstandClickListener {
            navigateToOtp(email)
            viewModel.resetUiState()
        }
        dialog.setOnResendClickListener {
            viewModel.submit()
        }
        dialog.show(childFragmentManager, "CheckEmailDialog")
    }

    private fun navigateToOtp(email: String?) {
        if (findNavController().currentDestination?.id == R.id.forgotPasswordFragment) {
            val args = Bundle().apply {
                putString(OtpVerificationFragment.ARG_EMAIL, email)
            }
            findNavController().navigate(
                R.id.action_forgotPasswordFragment_to_otpVerificationFragment,
                args
            )
        }
    }

    private fun hideMainChrome() {
        requireActivity().findViewById<BottomNavigationView>(R.id.bottomNav)?.visibility = View.GONE
        requireActivity().findViewById<FloatingActionButton>(R.id.fabChat)?.visibility = View.GONE
    }
}

